# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import SwiftUI
import UIKit

struct PromoData: Equatable {
    let code: String
    let discount: Int
}

final class UserAccountStore: ObservableObject {
    @Published var appliedPromo: PromoData?
    @Published var statusMessage: String = "No promo applied"

    func applyPromo(_ promo: PromoData) {
        appliedPromo = promo
        statusMessage = "Applied promo \(promo.code) for \(promo.discount)% off"
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()

    private init() {}

    func parsePromo(from url: URL) -> PromoData? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              components.host == "myapp.com",
              components.path == "/promo" else {
            return nil
        }

        let items = components.queryItems ?? []
        guard let code = items.first(where: { $0.name == "code" })?.value,
              !code.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              let discountString = items.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString),
              (0...100).contains(discount) else {
            return nil
        }

        return PromoData(code: code, discount: discount)
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    weak var userAccountStore: UserAccountStore?

    func application(
        _ application: UIApplication,
        continue userActivity: NSUserActivity,
        restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void
    ) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL,
              let promo = PromoLinkHandler.shared.parsePromo(from: url) else {
            return false
        }

        DispatchQueue.main.async { [weak self] in
            self?.userAccountStore?.applyPromo(promo)
        }
        return true
    }
}

struct ContentView: View {
    @EnvironmentObject var userAccountStore: UserAccountStore

    var body: some View {
        VStack(spacing: 16) {
            Text("Marketing Campaign Promo")
                .font(.title2)
                .bold()

            if let promo = userAccountStore.appliedPromo {
                Text("Promo Code: \(promo.code)")
                Text("Discount: \(promo.discount)%")
                    .foregroundColor(.green)
                    .bold()
            } else {
                Text("No active promotional offer")
                    .foregroundColor(.secondary)
            }

            Text(userAccountStore.statusMessage)
                .multilineTextAlignment(.center)
                .padding(.top, 8)
        }
        .padding()
        .onOpenURL { url in
            if let promo = PromoLinkHandler.shared.parsePromo(from: url) {
                userAccountStore.applyPromo(promo)
            }
        }
    }
}

@main
struct PromoUniversalLinksApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @StateObject private var userAccountStore = UserAccountStore()

    init() {}

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(userAccountStore)
                .onAppear {
                    appDelegate.userAccountStore = userAccountStore
                }
        }
    }
}